// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---

/**
 * Encode a compound cursor (created_at, id) into an opaque base64 string.
 */
function encodeCursor(row) {
    const payload = {
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64url');
}

/**
 * Decode an opaque cursor back into { created_at, id }.
 * Throws if the cursor is malformed or missing required fields.
 */
function decodeCursor(cursor) {
    let decoded;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        decoded = JSON.parse(json);
    } catch (err) {
        throw new Error('Malformed cursor');
    }

    if (
        decoded === null ||
        typeof decoded !== 'object' ||
        typeof decoded.id === 'undefined' ||
        typeof decoded.created_at === 'undefined'
    ) {
        throw new Error('Invalid cursor payload');
    }

    // Validate the timestamp is parseable.
    const ts = new Date(decoded.created_at);
    if (isNaN(ts.getTime())) {
        throw new Error('Invalid cursor timestamp');
    }

    return { created_at: decoded.created_at, id: decoded.id };
}

// --- Endpoint ---

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    limit = Math.min(Math.max(limit, 1), 100);

    const after = req.query.after;

    let cursor = null;
    if (after) {
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid pagination cursor' });
        }
    }

    // Build the query. Fetch limit + 1 rows to detect whether more pages exist.
    let sql;
    let params;

    if (cursor) {
        // Sort is (created_at DESC, id DESC), so "next" rows are strictly
        // "less than" the cursor under that ordering. The row-value comparison
        // (created_at, id) < (cursorCreatedAt, cursorId) expresses exactly that,
        // handling the created_at tie-break on id in one clause.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        params = [cursor.created_at, cursor.id, limit + 1];
    } else {
        // First page: no cursor filter.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);
    const rows = result.rows;

    // N+1 trick: if we got an extra row, there are more pages.
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}
```

## Key implementation notes

- **Row-value comparison** `(created_at, id) < ($1, $2)` is the heart of the conversion. Because the order is `created_at DESC, id DESC`, the "next" page consists of rows that are strictly *less than* the last row you saw under that ordering. PostgreSQL evaluates the tuple lexicographically, so this single predicate correctly handles the `created_at` tie-break on `id` — no fragile `OR (created_at = X AND id < Y)` expansion needed.
- **Index requirement:** for this to be fast, create a matching composite index: `CREATE INDEX ON posts (created_at DESC, id DESC) WHERE published = true;` (a partial index aligned with the `WHERE published = true` filter). The planner can then jump straight to the cursor position and scan forward.
- **`base64url`** is used instead of plain `base64` so cursors are URL-safe without needing percent-encoding in the query string.
- **Timestamp fidelity:** `created_at` is serialized as an ISO 8601 string in the cursor. With `timestamptz`, the comparison is unambiguous. If your column has sub-second precision, ISO 8601 preserves it; just make sure the DB column type and the encoded value agree on precision so the boundary row isn't skipped or repeated.

## Why cursor-based pagination is superior here

1. **Consistent performance at scale.** `OFFSET N` forces PostgreSQL to scan and discard N rows before returning results, so page 10,000 is dramatically slower than page 1. The cursor predicate uses the index to seek directly to the boundary, making every page roughly equally cheap (O(limit) instead of O(offset + limit)).
2. **No skipped or duplicated rows.** With offset pagination, if a new post is inserted (or one is deleted) while a user is paging through a feed sorted by `created_at DESC`, the offset window shifts and rows get duplicated or missed across pages. A cursor anchors to a specific `(created_at, id)` position, so concurrent inserts/deletes don't corrupt the result set.
3. **Dropping the COUNT query** removes a full-table aggregate that gets expensive on large tables and is rarely needed for infinite-scroll/feed UIs — `hasMore` answers "is there another page?" without counting everything.

The main trade-off: you lose random access to an arbitrary page number (no "jump to page 500"), which is exactly the right call for a chronological feed.

