// ─── Cursor Helpers ──────────────────────────────────────────────────────────

/**
 * Encodes a (created_at, id) pair into an opaque base64 cursor string.
 * @param {Date|string} created_at - Timestamp of the last row on the current page
 * @param {number|string} id       - ID of the last row on the current page
 * @returns {string} Base64-encoded cursor
 */
function encodeCursor(created_at, id) {
    const payload = JSON.stringify({
        created_at: created_at instanceof Date ? created_at.toISOString() : created_at,
        id: String(id),
    });
    return Buffer.from(payload, 'utf8').toString('base64');
}

/**
 * Decodes a base64 cursor string back into its component parts.
 * Returns null if the cursor is missing, malformed, or has unexpected shape.
 * @param {string} cursorStr - The raw cursor value from the query string
 * @returns {{ created_at: string, id: string } | null}
 */
function decodeCursor(cursorStr) {
    if (!cursorStr) return null;
    try {
        const raw = Buffer.from(cursorStr, 'base64').toString('utf8');
        const payload = JSON.parse(raw);

        // Structural validation — both fields must be present and non-empty
        if (
            typeof payload !== 'object' ||
            payload === null ||
            !payload.created_at ||
            payload.id === undefined ||
            payload.id === null
        ) {
            return null;
        }

        // Validate that created_at is a parseable date string
        if (isNaN(Date.parse(payload.created_at))) {
            return null;
        }

        return {
            created_at: payload.created_at,
            id: payload.id,
        };
    } catch {
        // JSON.parse failure or atob failure
        return null;
    }
}

// ─── Endpoint ────────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // Parse and cap limit to prevent abuse
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);

    // ── Decode cursor (if provided) ──────────────────────────────────────────
    let cursor = null;
    if (req.query.after !== undefined) {
        // `after` was explicitly provided — it must be valid
        cursor = decodeCursor(req.query.after);
        if (!cursor) {
            return res.status(400).json({
                error: 'Invalid cursor. The `after` parameter is malformed or expired.',
            });
        }
    }

    // ── Query: LIMIT N+1 trick ───────────────────────────────────────────────
    // Fetch one extra row. If we receive limit+1 rows, a next page exists.
    // No COUNT(*) query needed — it's O(N) on large tables and we don't need it.
    let result;

    if (cursor) {
        // Compound cursor condition for ORDER BY created_at DESC, id DESC:
        //   The next page begins at rows "before" the cursor in sort order, i.e.
        //   rows with an earlier created_at, OR the same created_at but a smaller id.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
             FROM posts
             WHERE published = true
               AND (
                       created_at < $1
                   OR (created_at = $1 AND id < $2)
               )
             ORDER BY created_at DESC, id DESC
             LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1]
        );
    } else {
        // First page — no cursor filter
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
             FROM posts
             WHERE published = true
             ORDER BY created_at DESC, id DESC
             LIMIT $1`,
            [limit + 1]
        );
    }

    // ── Apply N+1 trick ──────────────────────────────────────────────────────
    const hasMore = result.rows.length > limit;
    // Drop the extra sentinel row before returning to the client
    const posts = hasMore ? result.rows.slice(0, limit) : result.rows;

    // ── Build next cursor from the last row that will be returned ────────────
    let nextCursor = null;
    if (hasMore && posts.length > 0) {
        const last = posts[posts.length - 1];
        nextCursor = encodeCursor(last.created_at, last.id);
    }

    // ── Response ─────────────────────────────────────────────────────────────
    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,   // null when on the last page
            limit,
        },
    });
}
```

